const char *ts_embedded_query_get(const char *lang) {
    if (strcmp(lang, "bash") == 0) return ts_query_bash;
    if (strcmp(lang, "c") == 0) return ts_query_c;
    if (strcmp(lang, "cpp") == 0) return ts_query_cpp;
    if (strcmp(lang, "css") == 0) return ts_query_css;
    if (strcmp(lang, "go") == 0) return ts_query_go;
    if (strcmp(lang, "html") == 0) return ts_query_html;
    if (strcmp(lang, "java") == 0) return ts_query_java;
    if (strcmp(lang, "javascript") == 0) return ts_query_javascript;
    if (strcmp(lang, "json") == 0) return ts_query_json;
    if (strcmp(lang, "lua") == 0) return ts_query_lua;
    if (strcmp(lang, "python") == 0) return ts_query_python;
    if (strcmp(lang, "ruby") == 0) return ts_query_ruby;
    if (strcmp(lang, "rust") == 0) return ts_query_rust;
    if (strcmp(lang, "scheme") == 0) return ts_query_scheme;
    return NULL;
}

int ts_embedded_query_len(const char *lang) {
    if (strcmp(lang, "bash") == 0) return sizeof(ts_query_bash) - 1;
    if (strcmp(lang, "c") == 0) return sizeof(ts_query_c) - 1;
    if (strcmp(lang, "cpp") == 0) return sizeof(ts_query_cpp) - 1;
    if (strcmp(lang, "css") == 0) return sizeof(ts_query_css) - 1;
    if (strcmp(lang, "go") == 0) return sizeof(ts_query_go) - 1;
    if (strcmp(lang, "html") == 0) return sizeof(ts_query_html) - 1;
    if (strcmp(lang, "java") == 0) return sizeof(ts_query_java) - 1;
    if (strcmp(lang, "javascript") == 0) return sizeof(ts_query_javascript) - 1;
    if (strcmp(lang, "json") == 0) return sizeof(ts_query_json) - 1;
    if (strcmp(lang, "lua") == 0) return sizeof(ts_query_lua) - 1;
    if (strcmp(lang, "python") == 0) return sizeof(ts_query_python) - 1;
    if (strcmp(lang, "ruby") == 0) return sizeof(ts_query_ruby) - 1;
    if (strcmp(lang, "rust") == 0) return sizeof(ts_query_rust) - 1;
    if (strcmp(lang, "scheme") == 0) return sizeof(ts_query_scheme) - 1;
    return 0;
}
